export enum Section {
  NUMBER_SYSTEMS = "Number Systems & Arithmetic",
  EVERYDAY_MATH = "Everyday Mathematics",
  GEOMETRY_DATA = "Geometry & Data Handling",
  LOGICAL_REASONING = "Logical Reasoning",
  ACHIEVERS = "Achievers Section (HOTS)"
}

export interface Topic {
  id: string;
  name: string;
  description: string;
  section: Section;
}

export interface Question {
  id: string;
  text: string;
  options: string[];
  correctAnswer: number; // Index of correct option
  explanation: string;
  difficulty: "Easy" | "Medium" | "Hard";
}

export interface QuizState {
  questions: Question[];
  currentIndex: number;
  score: number;
  userAnswers: (number | null)[];
  isComplete: boolean;
  startTime: number;
  endTime?: number;
}

import { Section, Topic } from './types';

export const SYLLABUS: Topic[] = [
  // Number Systems
  { id: 'ns-1', name: 'Number Sense', description: '4-digit numbers, place value, face value, even/odd, roman numerals.', section: Section.NUMBER_SYSTEMS },
  { id: 'ns-2', name: 'Computation Operations', description: 'Addition, subtraction, multiplication, and division of multi-digit numbers.', section: Section.NUMBER_SYSTEMS },
  { id: 'ns-3', name: 'Fractions', description: 'Numerator, denominator, unit fractions, and collections.', section: Section.NUMBER_SYSTEMS },

  // Everyday Mathematics
  { id: 'em-1', name: 'Money', description: 'Currency, conversion, billing, and change calculation.', section: Section.EVERYDAY_MATH },
  { id: 'em-2', name: 'Time & Calendar', description: 'Clock reading, AM/PM, duration, and calendar concepts.', section: Section.EVERYDAY_MATH },
  { id: 'em-3', name: 'Measurement', description: 'Length (m/cm), weight (kg/g), capacity (l/ml), and temperature.', section: Section.EVERYDAY_MATH },

  // Geometry & Data
  { id: 'gd-1', name: 'Geometry', description: '2D & 3D shapes, lines (straight/curved), and spatial understanding.', section: Section.GEOMETRY_DATA },
  { id: 'gd-2', name: 'Data Handling', description: 'Pictographs, bar graphs, and tally marks.', section: Section.GEOMETRY_DATA },

  // Logical Reasoning
  { id: 'lr-1', name: 'Patterns & Analogy', description: 'Shape/number patterns and logical relationships.', section: Section.LOGICAL_REASONING },
  { id: 'lr-2', name: 'Coding-Decoding', description: 'Alpha-numeric codes and mirror images.', section: Section.LOGICAL_REASONING },
  { id: 'lr-3', name: 'Ranking & Embedded Figures', description: 'Positioning and finding hidden shapes.', section: Section.LOGICAL_REASONING },

  // HOTS
  { id: 'hots-1', name: 'Achievers Section', description: 'Higher Order Thinking Skills - Complex multi-step word problems.', section: Section.ACHIEVERS }
