import { GoogleGenAI, Type } from "@google/genai";
import { Question, Topic } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateQuestions(topic: Topic, count: number = 5): Promise<Question[]> {
  const prompt = `Generate ${count} multiple-choice Math Olympiad questions for a Class 3 student for the topic: "${topic.name}". 
  The difficulty should be appropriate for ${topic.section}.
  Ensure questions are challenging and focus on conceptual understanding, typical of IMO or SilverZone exams.
  For "Achievers Section", make them complex multi-step word problems.
  Return each question with 4 options, the index of the correct answer (0-3), and a simple explanation for kids.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING },
            options: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            correctAnswer: { type: Type.INTEGER },
            explanation: { type: Type.STRING },
            difficulty: { type: Type.STRING }
          },
          required: ['id', 'text', 'options', 'correctAnswer', 'explanation', 'difficulty']
        }
      }
    }
  });

  try {
    const text = response.text;
    return JSON.parse(text);
  } catch (error) {
    console.error("Failed to parse questions:", error);
    return [];
  }
}

