import React, { useState, useEffect } from 'react';
import { Question, QuizState, Topic } from '../types';
import { generateQuestions } from '../services/gemini';

interface QuizProps {
  topic?: Topic;
  isMock?: boolean;
  onComplete: (score: number, total: number) => void;
  onCancel: () => void;
}

const Quiz: React.FC<QuizProps> = ({ topic, isMock, onComplete, onCancel }) => {
  const [loading, setLoading] = useState(true);
  const [state, setState] = useState<QuizState | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);

  useEffect(() => {
    async function loadQuestions() {
      setLoading(true);
      try {
        let questions: Question[] = [];
        if (isMock) {
          // In a real app, we'd pick questions from across sections.
          // For demo, we'll generate 10 mixed questions.
          questions = await generateQuestions({ 
            id: 'mock', 
            name: 'Full Mock Test', 
            description: 'Mixed syllabus questions', 
            section: (null as any) 
          }, 10);
        } else if (topic) {
          questions = await generateQuestions(topic, 5);
        }

        setState({
          questions,
          currentIndex: 0,
          score: 0,
          userAnswers: Array(questions.length).fill(null),
          isComplete: false,
          startTime: Date.now()
        });
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    loadQuestions();
  }, [topic, isMock]);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] space-y-6">
        <div className="w-16 h-16 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
        <div className="text-center space-y-2">
          <h2 className="text-xl font-bold text-gray-800">Preparing Your {isMock ? 'Mock Test' : 'Practice Set'}</h2>
          <p className="text-gray-500">Gemini is gathering the best questions for you...</p>
        </div>
      </div>
    );
  }

  if (!state || state.questions.length === 0) {
    return (
      <div className="text-center py-12">
        <p className="text-red-500 mb-4">Failed to load questions. Please try again.</p>
        <button onClick={onCancel} className="text-indigo-600 font-bold">Back to Dashboard</button>
      </div>
    );
  }

  const currentQuestion = state.questions[state.currentIndex];
  const progress = ((state.currentIndex) / state.questions.length) * 100;

  const handleAnswerSelect = (index: number) => {
    if (state.userAnswers[state.currentIndex] !== null && !isMock) return;

    const newUserAnswers = [...state.userAnswers];
    newUserAnswers[state.currentIndex] = index;

    let newScore = state.score;
    if (index === currentQuestion.correctAnswer) {
      newScore += 1;
    }

    setState({
      ...state,
      userAnswers: newUserAnswers,
      score: newScore
    });

    if (!isMock) {
      setShowExplanation(true);
    }
  };

  const handleNext = () => {
    setShowExplanation(false);
    if (state.currentIndex < state.questions.length - 1) {
      setState({
        ...state,
        currentIndex: state.currentIndex + 1
      });
    } else {
      onComplete(state.score, state.questions.length);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8">
      {/* Header Info */}
      <div className="flex justify-between items-center bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
        <div className="flex items-center space-x-4">
          <button onClick={onCancel} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
            <svg className="w-5 h-5 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
          <div>
            <h3 className="font-bold text-gray-900">{isMock ? 'Full Mock Test' : topic?.name}</h3>
            <p className="text-xs text-gray-500 uppercase tracking-widest font-semibold">Question {state.currentIndex + 1} of {state.questions.length}</p>
          </div>
        </div>
        <div className="text-right">
          <div className="text-indigo-600 font-bold text-xl">{Math.floor((Date.now() - state.startTime) / 1000)}s</div>
          <p className="text-[10px] text-gray-400 font-bold uppercase">Time Elapsed</p>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="w-full bg-gray-100 h-3 rounded-full overflow-hidden">
        <div 
          className="bg-indigo-600 h-full transition-all duration-500" 
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      {/* Question Card */}
      <div className="bg-white rounded-3xl shadow-xl p-8 border border-gray-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4">
          <span className={`text-xs font-bold px-3 py-1 rounded-full ${
            currentQuestion.difficulty === 'Easy' ? 'bg-green-100 text-green-700' :
            currentQuestion.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
            'bg-red-100 text-red-700'
          }`}>
            {currentQuestion.difficulty}
          </span>
        </div>

        <div className="space-y-8">
          <h2 className="text-2xl font-bold text-gray-900 leading-tight">
            {currentQuestion.text}
          </h2>

          <div className="grid grid-cols-1 gap-4">
            {currentQuestion.options.map((option, idx) => {
              const isSelected = state.userAnswers[state.currentIndex] === idx;
              const isCorrect = idx === currentQuestion.correctAnswer;
              const showResult = !isMock && state.userAnswers[state.currentIndex] !== null;

              let buttonClass = "w-full p-5 rounded-2xl border-2 text-left transition-all duration-200 font-medium text-lg ";
              if (isSelected) {
                if (showResult) {
                  buttonClass += isCorrect ? "bg-green-50 border-green-500 text-green-700" : "bg-red-50 border-red-500 text-red-700";
                } else {
                  buttonClass += "bg-indigo-50 border-indigo-600 text-indigo-700";
                }
              } else if (showResult && isCorrect) {
                buttonClass += "bg-green-50 border-green-500 text-green-700";
              } else {
                buttonClass += "bg-white border-gray-100 hover:border-indigo-200 hover:bg-gray-50 text-gray-700";
              }

              return (
                <button
                  key={idx}
                  onClick={() => handleAnswerSelect(idx)}
                  disabled={showResult}
                  className={buttonClass}
                >
                  <div className="flex items-center space-x-4">
                    <span className={`w-8 h-8 flex items-center justify-center rounded-lg border text-sm font-bold ${
                      isSelected ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-gray-50 text-gray-400 border-gray-200'
                    }`}>
                      {String.fromCharCode(65 + idx)}
                    </span>
                    <span>{option}</span>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </div>

      {/* Feedback & Navigation */}
      <div className="min-h-[100px]">
        {showExplanation && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-6 animate-fadeIn">
            <h4 className="font-bold text-indigo-900 mb-2">Explanation</h4>
            <p className="text-indigo-800 text-sm leading-relaxed">{currentQuestion.explanation}</p>
          </div>
        )}

        <div className="mt-8 flex justify-end">
          <button
            onClick={handleNext}
            disabled={state.userAnswers[state.currentIndex] === null}
            className={`px-10 py-4 rounded-2xl font-bold text-white shadow-lg transition-all ${
              state.userAnswers[state.currentIndex] === null 
                ? 'bg-gray-300 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 transform hover:-translate-y-1'
            }`}
          >
            {state.currentIndex === state.questions.length - 1 ? 'Finish Quiz' : 'Next Question'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Quiz;

import React from 'react';

interface ResultScreenProps {
  score: number;
  total: number;
  onRestart: () => void;
  onGoHome: () => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ score, total, onRestart, onGoHome }) => {
  const percentage = (score / total) * 100;

  let message = "";
  let emoji = "";
  if (percentage === 100) { message = "Perfect Score! You're a Math Wizard!"; emoji = "🏆"; }
  else if (percentage >= 80) { message = "Excellent Job! Almost there!"; emoji = "🌟"; }
  else if (percentage >= 50) { message = "Good Effort! Keep practicing."; emoji = "💪"; }
  else { message = "Keep learning! You'll get better."; emoji = "📚"; }

  return (
    <div className="max-w-2xl mx-auto text-center space-y-12 py-10">
      <div className="space-y-4">
        <div className="text-7xl mb-4">{emoji}</div>
        <h1 className="text-4xl font-bold text-gray-900">{message}</h1>
        <p className="text-gray-500 text-lg">You completed the assessment successfully.</p>
      </div>

      <div className="bg-white rounded-3xl p-10 shadow-2xl border border-gray-100 space-y-8">
        <div className="grid grid-cols-2 gap-8">
          <div className="text-center p-6 bg-indigo-50 rounded-2xl">
            <div className="text-4xl font-black text-indigo-600">{score}/{total}</div>
            <div className="text-sm font-bold text-indigo-400 uppercase tracking-widest mt-2">Score</div>
          </div>
          <div className="text-center p-6 bg-purple-50 rounded-2xl">
            <div className="text-4xl font-black text-purple-600">{Math.round(percentage)}%</div>
            <div className="text-sm font-bold text-purple-400 uppercase tracking-widest mt-2">Accuracy</div>
          </div>
        </div>

        <div className="w-full bg-gray-100 h-4 rounded-full overflow-hidden">
          <div 
            className="bg-indigo-600 h-full rounded-full transition-all duration-1000" 
            style={{ width: `${percentage}%` }}
          ></div>
        </div>
      </div>

      <div className="flex flex-col sm:flex-row gap-4 justify-center">
        <button 
          onClick={onRestart}
          className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-xl"
        >
          Try Again
        </button>
        <button 
          onClick={onGoHome}
          className="bg-white text-gray-700 border border-gray-200 px-10 py-4 rounded-2xl font-bold hover:bg-gray-50 transition-all"
        >
          Back to Dashboard
        </button>
      </div>
    </div>
  );
};

export default ResultScreen;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Quiz from './components/Quiz';
import ResultScreen from './components/ResultScreen';
import { Topic } from './types';

enum View {
  DASHBOARD,
  QUIZ,
  RESULT
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [selectedTopic, setSelectedTopic] = useState<Topic | undefined>();
  const [isMockTest, setIsMockTest] = useState(false);
  const [lastResult, setLastResult] = useState<{ score: number; total: number } | null>(null);

  const handleStartPractice = (topic: Topic) => {
    setSelectedTopic(topic);
    setIsMockTest(false);
    setCurrentView(View.QUIZ);
  };

  const handleStartMock = () => {
    setSelectedTopic(undefined);
    setIsMockTest(true);
    setCurrentView(View.QUIZ);
  };

  const handleQuizComplete = (score: number, total: number) => {
    setLastResult({ score, total });
    setCurrentView(View.RESULT);
  };

  const handleGoHome = () => {
    setCurrentView(View.DASHBOARD);
    setSelectedTopic(undefined);
    setIsMockTest(false);
  };

  const handleRestart = () => {
    setCurrentView(View.QUIZ);
  };

  return (
    <Layout onGoHome={handleGoHome}>
      {currentView === View.DASHBOARD && (
        <Dashboard 
          onStartPractice={handleStartPractice} 
          onStartMock={handleStartMock} 
        />
      )}

      {currentView === View.QUIZ && (
        <Quiz 
          topic={selectedTopic} 
          isMock={isMockTest} 
          onComplete={handleQuizComplete}
          onCancel={handleGoHome}
        />
      )}

      {currentView === View.RESULT && lastResult && (
        <ResultScreen 
          score={lastResult.score} 
          total={lastResult.total} 
          onRestart={handleRestart}
          onGoHome={handleGoHome}
        />
      )}
    </Layout>
  );
};

export default App;

