import { GoogleGenAI, Type } from "@google/genai";
import { Question, Topic } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateQuestions(topic: Topic, count: number = 5): Promise<Question[]> {
  const prompt = `Generate ${count} high-quality Math Olympiad questions (Class 3 level) for: "${topic.name}".

  Style Requirements (Inspiration: SilverZone iOM, SOF IMO):
  - Focus on conceptual depth: number formation, symbolic puzzles (e.g., if square + circle = 10...), and multi-step logic.
  - Geometry questions should describe visual scenarios (e.g., "A figure made of 3 identical squares with total length 21cm, find perimeter").
  - Measurement questions should involve realistic scenarios (e.g., "Buying items with three 50 rupee notes").
  - Logical Reasoning should include patterns, series (e.g., 53, 48, 43...), and spatial visualization (counting cubes).
  - Use clear, professional phrasing appropriate for 8-9 year olds.

  Format: 4 options, 1 correct index (0-3), and a clear pedagogical explanation.
  Section: ${topic.section}.
  Difficulty: Mix of Medium and Hard.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING },
            options: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              minItems: 4,
              maxItems: 4
            },
            correctAnswer: { type: Type.INTEGER },
            explanation: { type: Type.STRING },
            difficulty: { type: Type.STRING }
          },
          required: ['id', 'text', 'options', 'correctAnswer', 'explanation', 'difficulty']
        }
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Failed to parse questions:", error);
    return [];
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Question, QuizState, Topic } from '../types';
import { generateQuestions } from '../services/gemini';

interface QuizProps {
  topic?: Topic;
  isMock?: boolean;
  onComplete: (score: number, total: number) => void;
  onCancel: () => void;
}

const Quiz: React.FC<QuizProps> = ({ topic, isMock, onComplete, onCancel }) => {
  const [loading, setLoading] = useState(true);
  const [state, setState] = useState<QuizState | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [timeLeft, setTimeLeft] = useState(isMock ? 3600 : 900); // 60 mins for mock, 15 for practice
  const timerRef = useRef<NodeJS.Timeout | null>(null);

