import React, { useState, useEffect, useRef } from 'react';
import { Question, QuizState, Topic } from '../types';
import { generateQuestions } from '../services/gemini';

interface QuizProps {
  topic?: Topic;
  isMock?: boolean;
  onComplete: (score: number, total: number) => void;
  onCancel: () => void;
}

const Quiz: React.FC<QuizProps> = ({ topic, isMock, onComplete, onCancel }) => {
  const [loading, setLoading] = useState(true);
  const [state, setState] = useState<QuizState | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [totalTimeLeft, setTotalTimeLeft] = useState(isMock ? 3600 : 900);
  const [questionSeconds, setQuestionSeconds] = useState(0);
  const [isTimeBlinking, setIsTimeBlinking] = useState(false);

  const timerRef = useRef<number | null>(null);
  const questionTimerRef = useRef<number | null>(null);

  // Suggested time per question (e.g., 60 seconds)
  const QUESTION_LIMIT = 60;

  useEffect(() => {
    async function loadQuestions() {
      setLoading(true);
      try {
        let questions: Question[] = [];
        const count = isMock ? 35 : 10;

        if (isMock) {
          const mockTopic = { 
            id: `mock-${Date.now()}`, 
            name: 'iOM Mock Test', 
            description: 'Comprehensive 35-question paper', 
            section: (null as any) 
          };
          questions = await generateQuestions(mockTopic, count);
        } else if (topic) {
          questions = await generateQuestions({ ...topic, id: `${topic.id}-${Date.now()}` }, count);
        }

        setState({
          questions,
          currentIndex: 0,
          score: 0,
          userAnswers: Array(questions.length).fill(null),
          isComplete: false,
          startTime: Date.now()
        });
        setQuestionSeconds(0);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    loadQuestions();
  }, [topic, isMock]);

  useEffect(() => {
    if (state && !state.isComplete) {
      timerRef.current = window.setInterval(() => {
        setTotalTimeLeft((prev) => {
          if (prev <= 1) {
            handleFinish();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);

      questionTimerRef.current = window.setInterval(() => {
        setQuestionSeconds(prev => {
          const next = prev + 1;
          if (next > QUESTION_LIMIT) {
            setIsTimeBlinking(true);
          }
          return next;
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
      if (questionTimerRef.current) window.clearInterval(questionTimerRef.current);
    };
  }, [state]);

  // Reset question timer when moving to a new question
  useEffect(() => {
    setQuestionSeconds(0);
    setIsTimeBlinking(false);
  }, [state?.currentIndex]);

  const handleFinish = () => {
    if (state) {
      onComplete(state.score, state.questions.length);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-6">
        <div className="w-16 h-16 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
        <div className="text-center space-y-2">
          <h2 className="text-2xl font-bold text-gray-800">Generating Fresh Questions...</h2>
          <p className="text-gray-500">Each test is unique. Preparing your paper now.</p>
        </div>
      </div>
    );
  }

  if (!state || state.questions.length === 0) {
    return (
      <div className="text-center py-12">
        <p className="text-red-500 mb-4 font-bold">Failed to load questions. Try again.</p>
        <button onClick={onCancel} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold">Back to Dashboard</button>
      </div>
    );
  }

  const currentQuestion = state.questions[state.currentIndex];
  const progress = ((state.currentIndex + 1) / state.questions.length) * 100;

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  const handleAnswerSelect = (index: number) => {
    if (state.userAnswers[state.currentIndex] !== null && !isMock) return;

    const newUserAnswers = [...state.userAnswers];
    newUserAnswers[state.currentIndex] = index;

    let newScore = 0;
    newUserAnswers.forEach((ans, idx) => {
      if (ans === state.questions[idx].correctAnswer) newScore++;
    });

    setState({
      ...state,
      userAnswers: newUserAnswers,
      score: newScore
    });

    if (!isMock) {
      setShowExplanation(true);
    }
  };

  const handleNext = () => {
    setShowExplanation(false);
    if (state.currentIndex < state.questions.length - 1) {
      setState({ ...state, currentIndex: state.currentIndex + 1 });
    } else {
      handleFinish();
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col px-8 py-6 bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
      {/* Quiz Header - Minimalized */}
      <div className="flex justify-between items-center mb-4 h-12 shrink-0">
        <div className="flex items-center space-x-3">
          <button onClick={onCancel} className="p-1.5 hover:bg-gray-100 rounded-full">
            <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
          <div>
            <h2 className="text-base font-bold text-gray-800 truncate leading-tight">{isMock ? 'iOM Sample Mock Test' : topic?.name}</h2>
            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-indigo-600 shrink-0">Q {state.currentIndex + 1}/{state.questions.length}</span>
              <div className="h-1 w-20 bg-gray-100 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${progress}%` }}></div>
              </div>
            </div>
          </div>
        </div>

        <div className="flex space-x-2">
          <div className={`px-3 py-1.5 rounded-lg flex items-center space-x-1.5 border transition-colors ${isTimeBlinking ? 'bg-red-50 border-red-200 animate-pulse' : 'bg-gray-50 border-gray-100'}`}>
            <span className="text-[9px] uppercase font-bold text-gray-400">Q-Time</span>
            <span className={`text-sm font-mono font-bold ${isTimeBlinking ? 'text-red-600' : 'text-gray-700'}`}>{formatTime(questionSeconds)}</span>
          </div>
          <div className={`px-3 py-1.5 rounded-lg flex items-center space-x-1.5 border ${totalTimeLeft < 300 ? 'bg-red-50 border-red-100 text-red-600' : 'bg-indigo-50 border-indigo-100 text-indigo-700'}`}>
            <span className="text-[9px] uppercase font-bold opacity-60">Total</span>
            <span className="text-sm font-mono font-bold">{formatTime(totalTimeLeft)}</span>
          </div>
        </div>
      </div>

      {/* Main Content Area - Layout designed to stay on one screen */}
      <div className="flex-grow flex flex-col justify-between min-h-0">
        {/* Question Text Area */}
        <div className="flex-shrink-0 py-2">
          <h3 className="text-xl md:text-2xl font-bold text-gray-900 leading-tight">
            {currentQuestion.text}
          </h3>
        </div>

        {/* Options Area - 4 columns on large screens to fit one line if possible */}
        <div className="flex-grow flex flex-col justify-center py-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
            {currentQuestion.options.map((option, idx) => {
              const isSelected = state.userAnswers[state.currentIndex] === idx;
              const isCorrect = idx === currentQuestion.correctAnswer;
              const showResult = !isMock && state.userAnswers[state.currentIndex] !== null;

              let btnStyle = "relative px-4 py-3 rounded-xl border-2 text-left transition-all group flex items-center h-full min-h-[56px] ";
              if (isSelected) {
                if (showResult) {
                  btnStyle += isCorrect ? "bg-green-50 border-green-500 text-green-700" : "bg-red-50 border-red-500 text-red-700";
                } else {
                  btnStyle += "bg-indigo-50 border-indigo-500 text-indigo-700";
                }
              } else if (showResult && isCorrect) {
                btnStyle += "bg-green-50 border-green-500 text-green-700";
              } else {
                btnStyle += "bg-white border-gray-100 hover:border-indigo-200 hover:bg-gray-50 text-gray-700";
              }

              return (
                <button
