import React, { useState, useEffect, useRef } from 'react';
import { Question, QuizState, Topic } from '../types';
import { generateQuestions } from '../services/gemini';

interface QuizProps {
  topic?: Topic;
  isMock?: boolean;
  onComplete: (score: number, questions: Question[], userAnswers: (number | null)[]) => void;
  onCancel: () => void;
}

const Quiz: React.FC<QuizProps> = ({ topic, isMock, onComplete, onCancel }) => {
  const [loading, setLoading] = useState(true);
  const [state, setState] = useState<QuizState | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [totalTimeLeft, setTotalTimeLeft] = useState(isMock ? 3600 : 900);
  const [questionSeconds, setQuestionSeconds] = useState(0);
  const [isTimeBlinking, setIsTimeBlinking] = useState(false);

  const timerRef = useRef<number | null>(null);
  const questionTimerRef = useRef<number | null>(null);

  // Suggested time per question (e.g., 60 seconds)
  const QUESTION_LIMIT = 60;

  useEffect(() => {
    async function loadQuestions() {
      setLoading(true);
      try {
        let questions: Question[] = [];
        const count = isMock ? 35 : 10;

        // Pass a dynamic timestamp to ensure unique context for generation
        const dynamicTopic = isMock 
          ? { id: `mock-${Date.now()}`, name: 'iOM Mock Test', description: 'Comprehensive 35-question paper', section: (null as any) }
          : { ...(topic as Topic), id: `${topic?.id}-${Date.now()}` };

        questions = await generateQuestions(dynamicTopic, count);

        setState({
          questions,
          currentIndex: 0,
          score: 0,
          userAnswers: Array(questions.length).fill(null),
          isComplete: false,
          startTime: Date.now()
        });
        setQuestionSeconds(0);
      } catch (err) {
        console.error("Quiz load error:", err);
      } finally {
        setLoading(false);
      }
    }
    loadQuestions();
  }, [topic, isMock]);

  useEffect(() => {
    if (state && !state.isComplete) {
      timerRef.current = window.setInterval(() => {
        setTotalTimeLeft((prev) => {
          if (prev <= 1) {
            handleFinish();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);

      questionTimerRef.current = window.setInterval(() => {
        setQuestionSeconds(prev => {
          const next = prev + 1;
          if (next > QUESTION_LIMIT) {
            setIsTimeBlinking(true);
          }
          return next;
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
      if (questionTimerRef.current) window.clearInterval(questionTimerRef.current);
    };
  }, [state]);

  // Reset question timer when moving to a new question
  useEffect(() => {
    setQuestionSeconds(0);
    setIsTimeBlinking(false);
  }, [state?.currentIndex]);

  const handleFinish = () => {
    if (state) {
      onComplete(state.score, state.questions, state.userAnswers);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  const handleAnswerSelect = (index: number) => {
    if (state!.userAnswers[state!.currentIndex] !== null && !isMock) return;

    const newState = { ...state! };
    newState.userAnswers[state!.currentIndex] = index;

    let newScore = 0;
    newState.userAnswers.forEach((ans, idx) => {
      if (ans === newState.questions[idx].correctAnswer) newScore++;
    });
    newState.score = newScore;

    setState(newState);

    if (!isMock) {
      setShowExplanation(true);
    }
  };

  const handleNext = () => {
    setShowExplanation(false);
    if (state!.currentIndex < state!.questions.length - 1) {
      setState({ ...state!, currentIndex: state!.currentIndex + 1 });
    } else {
      handleFinish();
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-6">
        <div className="w-16 h-16 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
        <div className="text-center space-y-2">
          <h2 className="text-2xl font-bold text-gray-800">Generating Fresh Questions...</h2>
          <p className="text-gray-500">Each session creates a unique set of challenges based on the syllabus.</p>
        </div>
      </div>
    );
  }

  if (!state || state.questions.length === 0) {
    return (
      <div className="text-center py-12">
        <p className="text-red-500 mb-4 font-bold">Failed to connect to the question bank.</p>
        <button onClick={onCancel} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold">Back to Dashboard</button>
      </div>
    );
  }

  const currentQuestion = state.questions[state.currentIndex];
  const progress = ((state.currentIndex + 1) / state.questions.length) * 100;

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col px-6 py-4 bg-white rounded-3xl shadow-2xl border border-gray-100 overflow-hidden">
      {/* Header - Very Slim */}
      <div className="flex justify-between items-center mb-3 h-10 shrink-0">
        <div className="flex items-center space-x-3">
          <button onClick={onCancel} className="p-1 hover:bg-gray-100 rounded-full transition-colors">
            <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
          <div className="flex flex-col">
            <h2 className="text-sm font-bold text-gray-800 truncate leading-none mb-1">{isMock ? 'Mock Examination' : topic?.name}</h2>
            <div className="flex items-center space-x-2">
              <span className="text-[10px] font-bold text-indigo-600 shrink-0">Q {state.currentIndex + 1}/{state.questions.length}</span>
              <div className="h-1 w-20 bg-gray-100 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${progress}%` }}></div>
              </div>
            </div>
          </div>
        </div>

        <div className="flex space-x-2">
          <div className={`px-2.5 py-1 rounded-lg flex items-center space-x-1.5 border transition-all duration-300 ${isTimeBlinking ? 'bg-red-50 border-red-200 animate-pulse' : 'bg-gray-50 border-gray-100'}`}>
            <span className="text-[8px] uppercase font-black text-gray-400">Q-Time</span>
            <span className={`text-xs font-mono font-bold ${isTimeBlinking ? 'text-red-600' : 'text-gray-700'}`}>{formatTime(questionSeconds)}</span>
          </div>
          <div className={`px-2.5 py-1 rounded-lg flex items-center space-x-1.5 border ${totalTimeLeft < 300 ? 'bg-red-50 border-red-100 text-red-600' : 'bg-indigo-50 border-indigo-100 text-indigo-700'}`}>
            <span className="text-[8px] uppercase font-black opacity-60">Total</span>
            <span className="text-xs font-mono font-bold">{formatTime(totalTimeLeft)}</span>
          </div>
        </div>
      </div>

      {/* Main content - Flex column to fill space without scrolling */}
      <div className="flex-grow flex flex-col justify-between min-h-0">
        {/* Question Area */}
        <div className="shrink-0 mb-4">
          <h3 className="text-lg md:text-xl font-bold text-gray-900 leading-snug">
            {currentQuestion.text}
          </h3>
        </div>

        {/* Options Area - 4 Columns for one-line appearance */}
        <div className="flex-grow flex items-center min-h-0 py-2">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 w-full">
            {currentQuestion.options.map((option, idx) => {
              const isSelected = state.userAnswers[state.currentIndex] === idx;
              const isCorrect = idx === currentQuestion.correctAnswer;
              const showResult = !isMock && state.userAnswers[state.currentIndex] !== null;

              let btnStyle = "relative px-4 py-3 rounded-xl border-2 text-left transition-all duration-200 group flex items-center h-full min-h-[64px] ";
              if (isSelected) {
                if (showResult) {
                  btnStyle += isCorrect ? "bg-green-50 border-green-500 text-green-700" : "bg-red-50 border-red-500 text-red-700";
                } else {
                  btnStyle += "bg-indigo-50 border-indigo-500 text-indigo-700";
                }
              } else if (showResult && isCorrect) {
                btnStyle += "bg-green-50 border-green-500 text-green-700";
              } else {
                btnStyle += "bg-white border-gray-100 hover:border-indigo-200 hover:bg-gray-50 text-gray-700";
              }

              return (
                <button
                  key={idx}
                  onClick={() => handleAnswerSelect(idx)}
                  disabled={showResult}
                  className={btnStyle}
                >
                  <span className={`w-6 h-6 rounded-md flex items-center justify-center font-bold mr-3 shrink-0 text-[10px] ${isSelected ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-400'}`}>
                    {String.fromCharCode(65 + idx)}
                  </span>
                  <span className="text-sm font-semibold leading-tight">{option}</span>
                </button>
              );
            })}
          </div>
        </div>

        {/* Feedback - Only visible when needed, occupies minimal height */}
        <div className={`transition-all duration-300 overflow-hidden ${showExplanation ? 'max-h-16 mt-2 opacity-100' : 'max-h-0 opacity-0'}`}>
          <div className="bg-amber-50 border-l-4 border-amber-400 p-2 rounded-r-lg h-full flex items-center">
            <p className="text-amber-900 font-medium italic text-[11px] leading-tight">"{currentQuestion.explanation}"</p>
          </div>
        </div>

        {/* Footer Navigation */}
        <div className="mt-3 pt-3 border-t border-gray-100 flex justify-between items-center shrink-0">
          <div className="text-[8px] font-black text-gray-300 uppercase tracking-widest">
            {isMock ? 'Mock Examination Active' : 'Topic Practice Mode'}
          </div>
          <div className="flex space-x-2">
            {state.currentIndex > 0 && (
              <button 
                onClick={() => setState({...state, currentIndex: state.currentIndex - 1})}
                className="px-4 py-1.5 rounded-lg border border-gray-200 font-bold text-gray-600 hover:bg-gray-50 text-[11px] transition-colors"
              >
                Previous
              </button>
            )}
            <button
              onClick={handleNext}
              disabled={state.userAnswers[state.currentIndex] === null}
              className={`px-6 py-2 rounded-lg font-bold text-white transition-all transform text-xs ${
                state.userAnswers[state.currentIndex] === null 
                  ? 'bg-gray-300 cursor-not-allowed opacity-50' 
                  : 'bg-indigo-600 hover:bg-indigo-700 hover:scale-105 shadow-md'
              }`}
            >
              {state.currentIndex === state.questions.length - 1 ? 'Finish Assessment' : 'Next Question'}
            </button>
          </div>
        </div>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.6; }
        }
        .animate-pulse {
          animation: pulse 1s cubic-bezier(0.4, 0, 0.6, 1) infinite;
        }
      `}} />
    </div>
  );
};

