import { Topic, Question, ReviewData } from './types';

enum View {
  DASHBOARD,
  QUIZ,
  RESULT,
  REVIEW
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [selectedTopic, setSelectedTopic] = useState<Topic | undefined>();
  const [isMockTest, setIsMockTest] = useState(false);
  const [lastResult, setLastResult] = useState<{ score: number; total: number } | null>(null);
  const [reviewData, setReviewData] = useState<ReviewData | null>(null);

  const handleStartPractice = (topic: Topic) => {
    setSelectedTopic(topic);
    setIsMockTest(false);
    setCurrentView(View.QUIZ);
  };

  const handleStartMock = () => {
    setSelectedTopic(undefined);
    setIsMockTest(true);
    setCurrentView(View.QUIZ);
  };

  const handleQuizComplete = (score: number, questions: Question[], userAnswers: (number | null)[]) => {
    const total = questions.length;
    setLastResult({ score, total });
    setReviewData({ questions, userAnswers, score, total });
    setCurrentView(View.RESULT);
  };

  const handleGoHome = () => {
    setCurrentView(View.DASHBOARD);
    setSelectedTopic(undefined);
    setIsMockTest(false);
  };

  const handleRestart = () => {
    setCurrentView(View.QUIZ);
  };

  const handleShowReview = () => {
    if (reviewData) {
      setCurrentView(View.REVIEW);
    }
  };

  const handleBackToResults = () => {
    setCurrentView(View.RESULT);
  };

  return (
    <Layout 
      onGoHome={handleGoHome} 
      onReviewPaper={handleShowReview} 
      hasReviewData={!!reviewData}
    >
      {currentView === View.DASHBOARD && (
        <Dashboard 
          onStartPractice={handleStartPractice} 
          onStartMock={handleStartMock} 
        />
      )}

      {currentView === View.QUIZ && (
        <Quiz 
          topic={selectedTopic} 
          isMock={isMockTest} 
          onComplete={handleQuizComplete}
          onCancel={handleGoHome}
        />
      )}

      {currentView === View.RESULT && lastResult && (
        <ResultScreen 
          score={lastResult.score} 
          total={lastResult.total} 
          onRestart={handleRestart}
          onGoHome={handleGoHome}
          onReview={handleShowReview}
        />
      )}

      {currentView === View.REVIEW && reviewData && (
        <ReviewScreen 
          questions={reviewData.questions}
          userAnswers={reviewData.userAnswers}
          onBack={handleBackToResults}
        />
      )}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Question, Topic } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateQuestions(topic: Topic, count: number = 5): Promise<Question[]> {
  const prompt = `Generate ${count} high-difficulty Math Olympiad questions for Class 3 students, specifically matching the elite standard of the SOF IMO (Achievers Section) and SilverZone IOM (Scholar's Section). 

  Topic: "${topic.name}" 
  Section: "${topic.section}"

  Difficulty Profile:
  - 80% of questions must be "Hard" (High-Order Thinking Skills - HOTS).
  - 20% should be "Medium" (Conceptual application).
  - Strictly avoid simple recall. Focus on logic, deduction, and multi-step arithmetic.

  Question Archetypes to implement:
  1. Multi-step Logic: Questions requiring at least 2-3 steps of calculation (e.g., "Find the difference between the largest 4-digit even number and the smallest 3-digit odd number").
  2. Symbolic Representation: "If 3 Stars = 15 and 1 Star + 2 Moons = 11, find the value of (2 Stars - 1 Moon)".
  3. Advanced Number Sense: Questions involving place value shifts, comparing non-standard forms, or "How many" questions (e.g., "How many numbers between 100 and 200 have the digit 7 in the units place?").
  4. Geometric Reasoning: Describing shapes and asking for vertices/edges plus a logic twist (e.g., "How many more edges does a cuboid have than a cylinder?").
  5. Logical Deduction: Patterns with hidden intervals or ranking/positioning puzzles.
  6. Distractors: Provide highly plausible but incorrect options based on common calculation slips children make.

  Output requirements:
  - Language: Clear, professional, and sophisticated for Class 3.
  - Options: Exactly 4 options.
  - Correct Answer: Integer index (0-3).
  - Explanation: Detailed, step-by-step pedagogical reasoning that explains the 'trick' or the logical path clearly.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 4000 },
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING },
            options: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              minItems: 4,
              maxItems: 4
            },
            correctAnswer: { type: Type.INTEGER },
            explanation: { type: Type.STRING },
            difficulty: { type: Type.STRING }
          },
          required: ['id', 'text', 'options', 'correctAnswer', 'explanation', 'difficulty']
        }
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Failed to parse questions:", error);
    return [];
  }
}

