import { GoogleGenAI, Type } from "@google/genai";
import { Question, Topic, UserPreferences, SyllabusData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function fetchDynamicSyllabus(prefs: UserPreferences): Promise<SyllabusData> {
  const prompt = `Research and provide the official and current (2024-2025) syllabus for ${prefs.examType} for Class ${prefs.className}. 
  The response must be in ${prefs.language}.
  Return the information as a structured JSON object representing the syllabus sections and topics.
  Include 4-5 main sections, each with an icon (emoji), a description, and 3-4 specific topics.
  Use Google Search to ensure the syllabus is accurate for the current year.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                icon: { type: Type.STRING },
                description: { type: Type.STRING },
                topics: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      id: { type: Type.STRING },
                      name: { type: Type.STRING },
                      description: { type: Type.STRING },
                      section: { type: Type.STRING }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text || '{}');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({ title: chunk.web?.title || 'Source', uri: chunk.web?.uri || '' }))
      .filter(s => s.uri);

    return { ...data, sources };
  } catch (error) {
    console.error("Syllabus parse error:", error);
    throw error;
  }
}

export async function generateQuestions(
  topic: Topic, 
  prefs: UserPreferences, 
  count: number = 5
): Promise<Question[]> {
  const prompt = `Generate ${count} highly challenging questions for ${prefs.examType} (Class ${prefs.className}) on the topic "${topic.name}".
  Language: ${prefs.language}.
  Use Google Search to find actual previous year patterns or model paper styles for this specific exam.
  Target the 'Achievers' or 'Scholar' level difficulty.

  Format: JSON array of questions with text, 4 options, correctAnswer index, explanation, and difficulty.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      thinkingConfig: { thinkingBudget: 4000 },
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING }, minItems: 4, maxItems: 4 },
            correctAnswer: { type: Type.INTEGER },
            explanation: { type: Type.STRING },
            difficulty: { type: Type.STRING }
          },
          required: ['id', 'text', 'options', 'correctAnswer', 'explanation', 'difficulty']
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Question parse error:", error);
    return [];
  }
}

