import { GoogleGenAI, Type } from "@google/genai";
import { Question, Topic, UserPreferences, SyllabusData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function fetchDynamicSyllabus(prefs: UserPreferences): Promise<SyllabusData> {
  const subjectStr = prefs.subject ? `Subject: ${prefs.subject}` : "";
  const prompt = `SEARCH GROUNDING REQUIRED: Research and provide the official, current (2024-2025) syllabus for the following:
  Exam: ${prefs.examType}
  Class: ${prefs.className}
  ${subjectStr}
  Language: ${prefs.language}

  INSTRUCTIONS:
  1. Use Google Search to find the latest curriculum, weightage, and major chapters.
  2. Create a comprehensive structure with 4-6 major sections.
  3. For each section, provide 3-5 granular topics/chapters that are likely to appear in the exam.
  4. Ensure all descriptions and names are in ${prefs.language}.
  5. The 'title' should be professional (e.g., "IIT-JEE Advanced 2025: Physics Comprehensive Syllabus").

  Return valid JSON matching the provided schema. Do not include markdown formatting outside the JSON block.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          examInfo: { type: Type.STRING },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                icon: { type: Type.STRING },
                description: { type: Type.STRING },
                topics: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      id: { type: Type.STRING },
                      name: { type: Type.STRING },
                      description: { type: Type.STRING },
                      section: { type: Type.STRING }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text || '{}');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({ title: chunk.web?.title || 'Source', uri: chunk.web?.uri || '' }))
      .filter(s => s.uri);

    return { ...data, sources };
  } catch (error) {
    console.error("Syllabus parse error:", error);
    throw new Error("Failed to generate syllabus. Please try again.");
  }
}

export async function generateQuestions(
  topic: Topic, 
  prefs: UserPreferences, 
  count: number = 5
): Promise<Question[]> {
  const subjectContext = prefs.subject ? `in ${prefs.subject}` : "";
  const prompt = `SEARCH GROUNDING REQUIRED: Act as an expert examiner for ${prefs.examType}.
  Generate ${count} elite-level questions for ${prefs.className} students on the topic "${topic.name}" ${subjectContext}.
  Language: ${prefs.language}.

  CRITICAL GUIDELINES:
  1. Use Google Search to verify the EXACT style and difficulty of ${prefs.examType}. 
  2. For JEE Advanced/NEET, include multi-concept problems, assertion-reason, or numerical style (adapted to MCQs).
  3. For Olympiads (IMO/SilverZone), focus on 'Achievers Section' difficulty.
  4. Every explanation must be a mini-masterclass in ${prefs.language}, explaining the logic/formula behind the correct answer.

  Format: JSON array of questions.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      thinkingConfig: { thinkingBudget: 4000 },
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING }, minItems: 4, maxItems: 4 },
            correctAnswer: { type: Type.INTEGER },
            explanation: { type: Type.STRING },
            difficulty: { type: Type.STRING }
          },
          required: ['id', 'text', 'options', 'correctAnswer', 'explanation', 'difficulty']
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Question parse error:", error);
    return [];
  }
}

