export async function fetchDynamicSyllabus(prefs: UserPreferences): Promise<SyllabusData> {
  const subjectStr = prefs.subject ? `Subject: ${prefs.subject}` : "";
  const prompt = `SEARCH GROUNDING REQUIRED: You are an expert education researcher. 
  Perform a live web search to find the official and latest (2024-2025 and 2025-2026) syllabus and examination pattern for:
  - Exam: ${prefs.examType}
  - Class: ${prefs.className}
  - ${subjectStr}
  - Preferred Language: ${prefs.language}

  Based on your search results, generate a structured syllabus including:
  1. A professional title (e.g., "Official Class 12 JEE Advanced 2025 Physics Curriculum").
  2. A brief summary of the current exam pattern found online.
  3. 4-6 major units/sections based on official weightage.
  4. 3-5 high-yield chapters/topics per section.

  CRITICAL:
  - Translate all content (titles, descriptions, topics) into ${prefs.language}.
  - Use Google Search to ensure high accuracy for ${prefs.examType} at the ${prefs.className} level.
  - If it's a competitive exam like JEE or NEET, focus on the specific ${subjectStr || 'curriculum'}.

  Return ONLY valid JSON matching the schema.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          examInfo: { type: Type.STRING },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                icon: { type: Type.STRING },
                description: { type: Type.STRING },
                topics: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      id: { type: Type.STRING },
                      name: { type: Type.STRING },
                      description: { type: Type.STRING },
                      section: { type: Type.STRING }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text || '{}');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({ title: chunk.web?.title || 'Source', uri: chunk.web?.uri || '' }))
      .filter(s => s.uri);

    return { ...data, sources };
  } catch (error) {
    console.error("Syllabus parse error:", error);
    throw new Error(`We couldn't research the syllabus for ${prefs.examType} (${prefs.className}). Please try again.`);
  }
}

