import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import SetupScreen from './components/SetupScreen';
import Dashboard from './components/Dashboard';
import Quiz from './components/Quiz';
import ResultScreen from './components/ResultScreen';
import ReviewScreen from './components/ReviewScreen';
import { Topic, Question, ReviewData, UserPreferences, SyllabusData } from './types';
import { fetchDynamicSyllabus } from './services/gemini';

enum View {
  SETUP,
  LOADING,
  DASHBOARD,
  QUIZ,
  RESULT,
  REVIEW
}

// Add global type for window.aistudio
declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.SETUP);
  const [prefs, setPrefs] = useState<UserPreferences | null>(null);
  const [syllabus, setSyllabus] = useState<SyllabusData | null>(null);
  const [selectedTopic, setSelectedTopic] = useState<Topic | undefined>();
  const [isMockTest, setIsMockTest] = useState(false);
  const [lastResult, setLastResult] = useState<{ score: number; total: number } | null>(null);
  const [reviewData, setReviewData] = useState<ReviewData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [keySelectionActive, setKeySelectionActive] = useState(false);

  const checkAndSelectKey = async () => {
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
      return true;
    } catch (e) {
      console.error("Key selection error:", e);
      return false;
    }
  };

  const handleSetupComplete = async (userPrefs: UserPreferences) => {
    setError(null);
    setPrefs(userPrefs);

    // Ensure API Key is selected as required for Pro model
    const keyReady = await checkAndSelectKey();
    if (!keyReady) {
      setError("API Key selection is required for research features.");
      return;
    }

    setCurrentView(View.LOADING);
    try {
      const data = await fetchDynamicSyllabus(userPrefs);
      if (!data || !data.sections || data.sections.length === 0) {
        throw new Error("No syllabus sections were found for this criteria.");
      }
      setSyllabus(data);
      setCurrentView(View.DASHBOARD);
    } catch (err: any) {
      console.error("Research failed:", err);
      if (err.message?.includes("entity was not found")) {
        // Handle specific race condition or invalid key
        await window.aistudio.openSelectKey();
        setError("Your project was not found. Please select a valid paid project key.");
      } else {
        setError(err.message || "Failed to research syllabus. Please try again.");
      }
      setCurrentView(View.SETUP);
    }
  };

  const handleStartPractice = (topic: Topic) => {
    setSelectedTopic(topic);
    setIsMockTest(false);
    setCurrentView(View.QUIZ);
  };

  const handleStartMock = () => {
    setSelectedTopic(undefined);
    setIsMockTest(true);
