import { GoogleGenAI, Type } from "@google/genai";
import { Question, Topic, UserPreferences, SyllabusData } from "../types";

export async function fetchDynamicSyllabus(prefs: UserPreferences): Promise<SyllabusData> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const subjectStr = prefs.subject ? `Subject: ${prefs.subject}` : "";

  const prompt = `SEARCH GROUNDING REQUIRED: You are a world-class academic researcher. 
  Perform an exhaustive web search for the CURRENT year (2024-2025 and 2025-2026) examination pattern, chapters, and marking scheme for:
  - Exam: ${prefs.examType}
  - Class: ${prefs.className}
  - ${subjectStr}
  - Language: ${prefs.language}

  Based on search results, provide:
  1. A specific title reflecting the exam and year.
  2. A summary of the latest marking scheme or exam changes found.
  3. A breakdown of 5-7 core units/modules as they appear in the latest official syllabus.
  4. 3-4 specific topics per unit.

  IMPORTANT:
  - Translate everything accurately into ${prefs.language}.
  - Focus on actual competitive trends.
  - DO NOT include topics that rely solely on external visual diagrams that cannot be described in text.
  - Use ONLY valid JSON matching the provided schema.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 4000 },
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            examInfo: { type: Type.STRING },
            sections: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  icon: { type: Type.STRING },
                  description: { type: Type.STRING },
                  topics: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        id: { type: Type.STRING },
                        name: { type: Type.STRING },
                        description: { type: Type.STRING },
                        section: { type: Type.STRING }
                      }
                    }
                  }
                }
              }
            }
          },
          required: ['title', 'examInfo', 'sections']
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({ title: chunk.web?.title || 'Source', uri: chunk.web?.uri || '' }))
      .filter(s => s.uri);

    return { ...data, sources };
  } catch (error) {
    console.error("Syllabus generation failed:", error);
    throw new Error("Syllabus research failed. Please check your connection and ensure your API key is active.");
  }
}

export async function generateQuestions(
  topic: Topic, 
  prefs: UserPreferences, 
  count: number = 5
): Promise<Question[]> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const subjectContext = prefs.subject ? `for ${prefs.subject}` : "";
  const prompt = `SEARCH GROUNDING REQUIRED: You are an elite question designer for ${prefs.examType}.
  Research the ACTUAL level and type of questions asked in recent (2023-2024) papers for:
  - Exam: ${prefs.examType}
  - Class: ${prefs.className}
  - Chapter/Topic: "${topic.name}" ${subjectContext}
  - Language: ${prefs.language}

  Generate ${count} original, high-difficulty questions matching the target exam's standard.

  STRICT CONTENT RULES:
  1. NO IMAGES/DIAGRAMS: Do not create questions that refer to "the image above", "the figure shown", or "the diagram".
  2. TEXT-ONLY DESCRIPTIONS: If a question normally requires a shape or graph, describe the properties in detail using text (e.g., "A rectangle has a length of 10cm and a width of 5cm...").
  3. CONCEPTUAL FOCUS: Prioritize logic, calculations, and multi-step reasoning that can be solved purely through reading.
  4. LANGUAGE: All text and explanations MUST be in ${prefs.language}.

  Format as JSON array of questions.`;

  try {
